	for x := l; x <= r; x++ {
		// 1. Format x as a 16-digit string with leading zeros
		xStr := strconv.FormatInt(x, 10)
		paddedX := ""
		for len(paddedX) < 16-len(xStr) {
			paddedX += "0"
		}
		paddedX += xStr

		// 2. Fill 4x4 grid
		grid := make([][4]int, 4)

		for i := 0; i < 16; i++ {
			digit := int(paddedX[i] - '0')
			row := i / 4
			col := i % 4
			grid[row][col] = digit
		}

		// 3. Determine the path and record the sequence
		row := 0
		col := 0
		sequence := make([]int, 0, 7)

		// Start at (0, 0)
		sequence = append(sequence, grid[row][col])

		// Apply 6 moves
		for i := 0; i < 6; i++ {
			move := directions[i]
			if move == 'D' {
				row += 1
			} else if move == 'R' {
				col += 1
			}

			// The problem implies the path stays within bounds 4x4.
			// If it goes out of bounds, we assume it stops or handles it according to grid access,
			// but based on the problem description and constraints (3 'D', 3 'R'),
			// the maximum row change is 3, max col change is 3, so it stays in [0, 3] x [0, 3].
			if row >= 0 && row < 4 && col >= 0 && col < 4 {
				sequence = append(sequence, grid[row][col])
			}
		}

		// 4. Check for non-decreasing property
		isGood := true
		for i := 0; i < len(sequence)-1; i++ {
			if sequence[i] > sequence[i+1] {
				isGood = false
				break
			}
		}

		if isGood {
			goodCount++
		}
	}

	return goodCount
}
