function solve(lStr, rStr, directions) {
    const L = BigInt(lStr);
    const R = BigInt(rStr);
    let goodCount = 0;

    for (let xBig = L; xBig <= R; xBig++) {
        const x = xBig.toString().padStart(16, '0');

        // 1. Fill 4x4 grid
        const grid = Array(4).fill(0).map(() => Array(4).fill(0));

        for (let i = 0; i < 16; i++) {
            const digit = parseInt(x[i]);
            const row = Math.floor(i / 4);
            const col = i % 4;
            grid[row][col] = digit;
        }

        // 2. Determine the path
        let row = 0;
        let col = 0;
        const path = [{ r: row, c: col }];

        // 6 moves defined by directions
        for (let i = 0; i < 6; i++) {
            const move = directions[i];
            if (move === 'D') {
                row += 1;
            } else if (move === 'R') {
                col += 1;
            }

            // Boundary check (though problem constraints imply path stays within bounds if it's well-formed)
            if (row >= 0 && row < 4 && col >= 0 && col < 4) {
                path.push({ r: row, c: col });
            }
        }

        // 3. Record the sequence of visited digits (length 7)
        const sequence = [];
        for (const { r, c } of path) {
            // Assuming the path always has length 7 as per problem statement (1 start + 6 moves)
            sequence.push(grid[r][c]);
        }

        // 4. Check for non-decreasing property
        let isGood = true;
        for (let i = 0; i < sequence.length - 1; i++) {
            if (sequence[i] > sequence[i+1]) {
                isGood = false;
                break;
            }
        }

        if (isGood) {
            goodCount++;
        }
